// Type annotations make your intentions clear
let age: number = 30;        // whole numbers
let isActive: boolean = true; // true or false

// TypeScript infers 'string' from the assigned value
let message = 'Hello, world!';

// Inferred as 'number' -- no annotation needed
let count = 42;

// | means 'or' -- userId accepts strings OR numbers
let userId: string | number;

userId = 'abc123';  // a string is valid
userId = 42;         // a number is also valid

// type creates a reusable alias -- write it once, use everywhere
type ID = string | number;

function lookup(id: ID): string {
  return 'user_' + id;
}

// The type is the exact value, not just 'string'
let direction: 'up' | 'down' | 'left' | 'right';

direction = 'up';         // OK -- matches one of the literals
direction = 'diagonal';   // Error at compile time -- not in the set
